package com.example.webviewwrapper

import android.Manifest
import android.app.Activity
import android.content.Intent
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.provider.MediaStore
import android.webkit.*
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import com.google.android.gms.tasks.OnCompleteListener
import com.google.firebase.messaging.FirebaseMessaging
import org.json.JSONObject
import java.io.File
import java.io.IOException
import java.text.SimpleDateFormat
import java.util.*

class MainActivity : AppCompatActivity() {

    private lateinit var webView: WebView
    private var cameraImageUri: Uri? = null
    private var filePathCallback: ValueCallback<Array<Uri>>? = null

    private val cameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            openCamera()
        } else {
            Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show()
        }
    }

    private val cameraLauncher = registerForActivityResult(
        ActivityResultContracts.TakePicture()
    ) { success ->
        if (success && cameraImageUri != null) {
            filePathCallback?.onReceiveValue(arrayOf(cameraImageUri!!))
        } else {
            filePathCallback?.onReceiveValue(null)
        }
        filePathCallback = null
    }

    private val fileChooserLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            val data = result.data
            val results = if (data?.data != null) {
                arrayOf(data.data!!)
            } else {
                null
            }
            filePathCallback?.onReceiveValue(results)
        } else {
            filePathCallback?.onReceiveValue(null)
        }
        filePathCallback = null
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        webView = findViewById(R.id.webView)
        setupWebView()
        
        webView.loadUrl("https://yourdomain.com")
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = false
            allowContentAccess = true
            
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
                mixedContentMode = WebSettings.MIXED_CONTENT_NEVER_ALLOW
            }
            
            setSupportZoom(true)
            builtInZoomControls = true
            displayZoomControls = false
            
            cacheMode = WebSettings.LOAD_DEFAULT
            
            userAgentString = "$userAgentString AppName/1.0"
        }

        webView.addJavascriptInterface(WebAppInterface(this), "AndroidBridge")

        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                val url = request?.url?.toString() ?: return false
                
                if (url.startsWith("https://yourdomain.com")) {
                    return false
                }
                
                if (url.startsWith("http://") || url.startsWith("https://")) {
                    val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                    startActivity(intent)
                    return true
                }
                
                return true
            }

            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
            }

            override fun onReceivedError(view: WebView?, request: WebResourceRequest?, error: WebResourceError?) {
                super.onReceivedError(view, request, error)
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
                    Toast.makeText(this@MainActivity, "Error: ${error?.description}", Toast.LENGTH_SHORT).show()
                }
            }

            override fun onReceivedSslError(view: WebView?, handler: SslErrorHandler?, error: SslError?) {
                handler?.cancel()
                Toast.makeText(this@MainActivity, "SSL Error", Toast.LENGTH_SHORT).show()
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                this@MainActivity.filePathCallback?.onReceiveValue(null)
                this@MainActivity.filePathCallback = filePathCallback

                val acceptTypes = fileChooserParams?.acceptTypes
                val captureEnabled = fileChooserParams?.isCaptureEnabled ?: false

                if (captureEnabled && acceptTypes?.contains("image/*") == true) {
                    if (ContextCompat.checkSelfPermission(this@MainActivity, Manifest.permission.CAMERA) 
                        == PackageManager.PERMISSION_GRANTED) {
                        openCamera()
                    } else {
                        cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
                    }
                } else {
                    val intent = Intent(Intent.ACTION_GET_CONTENT)
                    intent.addCategory(Intent.CATEGORY_OPENABLE)
                    intent.type = "*/*"
                    fileChooserLauncher.launch(intent)
                }

                return true
            }

            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                consoleMessage?.let {
                    android.util.Log.d("WebView", "${it.message()} -- From line ${it.lineNumber()} of ${it.sourceId()}")
                }
                return true
            }

            override fun onPermissionRequest(request: PermissionRequest?) {
                request?.let {
                    val requestedResources = it.resources
                    for (resource in requestedResources) {
                        when (resource) {
                            PermissionRequest.RESOURCE_VIDEO_CAPTURE,
                            PermissionRequest.RESOURCE_AUDIO_CAPTURE -> {
                                it.deny()
                            }
                        }
                    }
                }
            }
        }

        CookieManager.getInstance().setAcceptThirdPartyCookies(webView, false)
    }

    private fun openCamera() {
        val photoFile: File? = try {
            createImageFile()
        } catch (ex: IOException) {
            null
        }

        photoFile?.also {
            cameraImageUri = FileProvider.getUriForFile(
                this,
                "${applicationContext.packageName}.fileprovider",
                it
            )
            cameraLauncher.launch(cameraImageUri)
        }
    }

    @Throws(IOException::class)
    private fun createImageFile(): File {
        val timeStamp: String = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val storageDir: File? = getExternalFilesDir(null)
        return File.createTempFile(
            "JPEG_${timeStamp}_",
            ".jpg",
            storageDir
        )
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    inner class WebAppInterface(private val activity: MainActivity) {

        @JavascriptInterface
        fun requestCameraAccess() {
            activity.runOnUiThread {
                if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) 
                    == PackageManager.PERMISSION_GRANTED) {
                    notifyWebView("cameraPermissionGranted", true)
                } else {
                    ActivityCompat.requestPermissions(
                        activity,
                        arrayOf(Manifest.permission.CAMERA),
                        CAMERA_PERMISSION_REQUEST_CODE
                    )
                }
            }
        }

        @JavascriptInterface
        fun saveToLocalStorage(key: String, value: String) {
            val sharedPreferences = activity.getSharedPreferences("WebAppStorage", MODE_PRIVATE)
            sharedPreferences.edit().putString(key, value).apply()
        }

        @JavascriptInterface
        fun getFromLocalStorage(key: String): String? {
            val sharedPreferences = activity.getSharedPreferences("WebAppStorage", MODE_PRIVATE)
            return sharedPreferences.getString(key, null)
        }

        @JavascriptInterface
        fun removeFromLocalStorage(key: String) {
            val sharedPreferences = activity.getSharedPreferences("WebAppStorage", MODE_PRIVATE)
            sharedPreferences.edit().remove(key).apply()
        }

        @JavascriptInterface
        fun clearLocalStorage() {
            val sharedPreferences = activity.getSharedPreferences("WebAppStorage", MODE_PRIVATE)
            sharedPreferences.edit().clear().apply()
        }

        @JavascriptInterface
        fun requestPushNotificationPermission() {
            activity.runOnUiThread {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                    if (ContextCompat.checkSelfPermission(activity, Manifest.permission.POST_NOTIFICATIONS) 
                        == PackageManager.PERMISSION_GRANTED) {
                        registerForPushNotifications()
                    } else {
                        ActivityCompat.requestPermissions(
                            activity,
                            arrayOf(Manifest.permission.POST_NOTIFICATIONS),
                            NOTIFICATION_PERMISSION_REQUEST_CODE
                        )
                    }
                } else {
                    registerForPushNotifications()
                }
            }
        }

        @JavascriptInterface
        fun getPushNotificationToken(): String? {
            val sharedPreferences = activity.getSharedPreferences("WebAppStorage", MODE_PRIVATE)
            return sharedPreferences.getString("fcm_token", null)
        }

        @JavascriptInterface
        fun showToast(message: String) {
            activity.runOnUiThread {
                Toast.makeText(activity, message, Toast.LENGTH_SHORT).show()
            }
        }

        @JavascriptInterface
        fun getDeviceInfo(): String {
            val deviceInfo = JSONObject()
            deviceInfo.put("model", Build.MODEL)
            deviceInfo.put("manufacturer", Build.MANUFACTURER)
            deviceInfo.put("osVersion", Build.VERSION.RELEASE)
            deviceInfo.put("sdkVersion", Build.VERSION.SDK_INT)
            return deviceInfo.toString()
        }

        private fun notifyWebView(event: String, data: Any) {
            val json = JSONObject()
            json.put("event", event)
            json.put("data", data)
            
            activity.runOnUiThread {
                webView.evaluateJavascript(
                    "window.dispatchEvent(new CustomEvent('nativeEvent', { detail: $json }));",
                    null
                )
            }
        }

        private fun registerForPushNotifications() {
            FirebaseMessaging.getInstance().token.addOnCompleteListener(OnCompleteListener { task ->
                if (!task.isSuccessful) {
                    notifyWebView("pushNotificationError", "Failed to get token")
                    return@OnCompleteListener
                }

                val token = task.result
                val sharedPreferences = activity.getSharedPreferences("WebAppStorage", MODE_PRIVATE)
                sharedPreferences.edit().putString("fcm_token", token).apply()
                
                notifyWebView("pushNotificationToken", token ?: "")
            })
        }
    }

    override fun onRequestPermissionsResult(
        requestCode: Int,
        permissions: Array<out String>,
        grantResults: IntArray
    ) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults)
        
        when (requestCode) {
            CAMERA_PERMISSION_REQUEST_CODE -> {
                if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    webView.evaluateJavascript(
                        "window.dispatchEvent(new CustomEvent('nativeEvent', { detail: { event: 'cameraPermissionGranted', data: true } }));",
                        null
                    )
                } else {
                    webView.evaluateJavascript(
                        "window.dispatchEvent(new CustomEvent('nativeEvent', { detail: { event: 'cameraPermissionGranted', data: false } }));",
                        null
                    )
                }
            }
            NOTIFICATION_PERMISSION_REQUEST_CODE -> {
                if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                    (webView.getTag() as? WebAppInterface)?.let {
                        // Permission granted, register for push notifications
                    }
                }
            }
        }
    }

    companion object {
        private const val CAMERA_PERMISSION_REQUEST_CODE = 100
        private const val NOTIFICATION_PERMISSION_REQUEST_CODE = 101
    }
}